  z-index: 50;
  list-style: none;
  padding: 0.25rem 0;
  margin: 0.25rem 0 0;
}

.ac__option {
  padding: 0.5rem 0.75rem;
  font-size: 0.875rem;
  color: #374151;
  cursor: pointer;
  transition: background-color 0.1s ease;
}

.ac__option:hover {
  background: #eff6ff;
  color: #1d4ed8;
}

.ac__option mark {
  background: #fef08a;
  color: inherit;
  border-radius: 2px;
  padding: 0 1px;
}

.ac__no-results {
  padding: 0.625rem 0.75rem;
  font-size: 0.8125rem;
  color: #9ca3af;
  font-style: italic;
}

