import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { Autocomplete } from './Autocomplete';

const ITEMS = ['Apple', 'Apricot', 'Banana', 'Cherry'];

describe('Autocomplete', () => {
  it('shows dropdown with all items when input is focused and empty', () => {
    render(<Autocomplete suggestions={ITEMS} />);
    fireEvent.focus(screen.getByTestId('ac-input'));
    expect(screen.getByTestId('ac-dropdown')).toBeInTheDocument();
    expect(screen.getByTestId('ac-option-0')).toHaveTextContent('Apple');
    expect(screen.getByTestId('ac-option-3')).toHaveTextContent('Cherry');
  });

  it('filters suggestions as user types', () => {
    render(<Autocomplete suggestions={ITEMS} />);
    const input = screen.getByTestId('ac-input');
    fireEvent.focus(input);
    fireEvent.change(input, { target: { value: 'ap' } });
    expect(screen.getByTestId('ac-option-0')).toHaveTextContent('Apple');
    expect(screen.getByTestId('ac-option-1')).toHaveTextContent('Apricot');
    expect(screen.queryByText('Banana')).not.toBeInTheDocument();
  });

  it('is case-insensitive', () => {
    render(<Autocomplete suggestions={ITEMS} />);
    const input = screen.getByTestId('ac-input');
    fireEvent.focus(input);
    fireEvent.change(input, { target: { value: 'CHERRY' } });
    expect(screen.getByTestId('ac-option-0')).toHaveTextContent('Cherry');
  });

  it('fills input and closes dropdown when suggestion is clicked', () => {
    render(<Autocomplete suggestions={ITEMS} />);
    const input = screen.getByTestId('ac-input');
    fireEvent.focus(input);
    fireEvent.mouseDown(screen.getByTestId('ac-option-2'));
    expect(input).toHaveValue('Banana');
    expect(screen.queryByTestId('ac-dropdown')).not.toBeInTheDocument();
  });

  it('closes dropdown on Escape key', () => {
    render(<Autocomplete suggestions={ITEMS} />);
    const input = screen.getByTestId('ac-input');
    fireEvent.focus(input);
    expect(screen.getByTestId('ac-dropdown')).toBeInTheDocument();
    fireEvent.keyDown(input, { key: 'Escape' });
    expect(screen.queryByTestId('ac-dropdown')).not.toBeInTheDocument();
  });

  it('shows no-results message when nothing matches', () => {
    render(<Autocomplete suggestions={ITEMS} />);
    const input = screen.getByTestId('ac-input');
    fireEvent.focus(input);
    fireEvent.change(input, { target: { value: 'xyz' } });
    expect(screen.getByTestId('ac-no-results')).toHaveTextContent('No results');
  });

  it('calls onSelect when a suggestion is chosen', () => {
    const spy = jest.fn();
    render(<Autocomplete suggestions={ITEMS} onSelect={spy} />);
    fireEvent.focus(screen.getByTestId('ac-input'));
    fireEvent.mouseDown(screen.getByTestId('ac-option-0'));
    expect(spy).toHaveBeenCalledWith('Apple');
  });
});

